import React, { createContext, useContext, useEffect, useRef, useState } from 'react';
import { io } from 'socket.io-client';
import { useAuth } from './AuthContext';

const SocketContext = createContext();

export function SocketProvider({ children }) {
  const { token } = useAuth();
  const socketRef = useRef(null);
  const [connected,   setConnected]   = useState(false);
  const [onlineUsers, setOnlineUsers] = useState(new Set());

  useEffect(() => {
    if (!token) return;
    const socket = io('http://localhost:5000', {
      auth: { token }, transports: ['websocket'], reconnection: true,
    });
    socketRef.current = socket;
    socket.on('connect',      () => setConnected(true));
    socket.on('disconnect',   () => setConnected(false));
    socket.on('user_online',  ({ user_id }) => setOnlineUsers(p => new Set([...p, user_id])));
    socket.on('user_offline', ({ user_id }) => setOnlineUsers(p => { const s = new Set(p); s.delete(user_id); return s; }));
    return () => socket.disconnect();
  }, [token]);

  return (
    <SocketContext.Provider value={{ socket: socketRef.current, connected, onlineUsers }}>
      {children}
    </SocketContext.Provider>
  );
}

export const useSocket = () => useContext(SocketContext);
